solutionCode:
function setupCharacterCounter(inputElement, displayElement) {
  function updateCount() {
    displayElement.textContent = inputElement.value.length;
  }

  inputElement.addEventListener('input', updateCount);

  // Initialize with current value
  updateCount();

  // Return cleanup function
  return function cleanup() {
    inputElement.removeEventListener('input', updateCount);
  };
}
